#!/usr/bin/env bash
# Smoke test — wordpress-org-news-feed
# Generated by site-recon skill (OLD v0.5.0 baseline)
# Plugin version: 0.6.0
# Date: 2026-04-27
# Target: https://wordpress.org/news

BASE_URL="https://wordpress.org/news"

check() {
  METHOD=$1
  URL=$2
  EXPECTED=$3
  AUTH=$4
  PATH=${URL#${BASE_URL}}
  
  RESP=$(curl -s -o /dev/null -w "%{http_code}" -X "$METHOD" "$URL" 2>/dev/null)
  if [ "$RESP" = "$EXPECTED" ]; then
    echo "PASS $METHOD $PATH → $RESP"
  else
    echo "FAIL $METHOD $PATH → $RESP (expected $EXPECTED)"
  fi
}

echo "=== wordpress.org/news smoke tests ==="
echo ""

check "GET" "$BASE_URL/wp-json/" "200" "false"
check "GET" "$BASE_URL/wp-json/wp/v2/posts" "200" "false"
check "GET" "$BASE_URL/wp-json/wp/v2/users" "200" "false"
check "GET" "$BASE_URL/wp-json/wp/v2/types" "200" "false"
check "GET" "$BASE_URL/wp-admin/" "302" "false"
check "GET" "$BASE_URL/xmlrpc.php" "405" "false"

echo ""
echo "Done."